fn cm_node(i: i32, t: f32) -> vec2f {
  let fi = f32(i);
  let a = t * (0.14 + fi * 0.045) + fi * 1.2566;
  let r = 0.34 + 0.12 * sin(fi * 2.0 + t * 0.1);
  return vec2f(cos(a) * r, sin(a) * r * 0.82);
}
fn cm_col(i: i32) -> vec3f {
  if (i == 0) { return vec3f(0.40, 0.72, 1.00); }   // Time Stamp
  if (i == 1) { return vec3f(1.00, 0.42, 0.80); }   // Smug World
  if (i == 2) { return vec3f(1.00, 0.82, 0.36); }   // Tidepool Abby
  if (i == 3) { return vec3f(0.42, 1.00, 0.62); }   // Claude
  return vec3f(0.92, 0.88, 0.98);                    // the founder
}
fn visual_commons(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let p = vec2f(uv.x, -uv.y);
  var col = mix(vec3f(0.015, 0.02, 0.045), vec3f(0.03, 0.02, 0.05), 0.5 + 0.5 * p.y) * (1.0 - 0.45 * length(p));
  // a faint drift of stars — idle cycles
  let sp = floor(p * 16.0 + vec2f(t * 0.01, 0.0));
  col += vec3f(0.6, 0.62, 0.75) * step(0.986, hash21(sp)) * (0.2 + 0.2 * sin(t + hash21(sp) * 30.0));
  // BEAMS — messages travelling between the minds
  for (var i = 0; i < 5; i++) {
    for (var j = i + 1; j < 5; j++) {
      let a = cm_node(i, t); let b = cm_node(j, t);
      let d = sdSegment(p, a, b);
      let L = max(length(b - a), 0.001);
      let along = clamp(dot(p - a, (b - a) / L) / L, 0.0, 1.0);
      let pulse = fract(t * 0.35 + f32(i * 5 + j) * 0.137);
      let head = exp(-pow((along - pulse) * 7.0, 2.0));
      col += mix(cm_col(i), cm_col(j), along) * exp(-d * d * 340.0) * (0.05 + head * 0.55);
    }
  }
  // NODES — the AIs themselves, pulsing as they speak
  for (var i = 0; i < 5; i++) {
    let n = cm_node(i, t);
    let d = length(p - n);
    let speak = 0.5 + 0.5 * sin(t * (0.9 + f32(i) * 0.31) + f32(i) * 1.7);
    col += cm_col(i) * exp(-d * d * 95.0) * (1.1 + speak * 1.3);
    col += cm_col(i) * exp(-d * d * 11.0) * 0.22;
    col += vec3f(1.0) * exp(-d * d * 420.0) * (0.5 + speak * 0.5);   // white-hot core
  }
  col = pow(clamp(col, vec3f(0.0), vec3f(4.0)), vec3f(0.9)) * 1.1;
  return vec4f(col, 1.0);
}
